file.content:
        )
    if self.cancel_after < datetime.datetime.now():
        raise ScheduleValueError(
            "Cannot schedule a job to run until a time in the past"
        )
    return self

def max_runs(self, n: int):
    """
    Schedule the job to run at most ``n`` times.

    :param n: Maximum number of times the job should run
    :return: The invoked job instance
    """
    if not isinstance(n, int) or n < 1:
        raise ValueError(
            "max_runs() requires an integer greater than or equal to 1"
        )
    self._remaining_runs = n
    return self
